mapper.select:
SELECT id, project_key, name, description, created_at, updated_at
FROM management_app.projects
WHERE id = #{id}

SELECT id, project_key, name, description, created_at, updated_at
FROM management_app.projects
WHERE project_key = #{projectKey}

SELECT EXISTS (
  SELECT 1
  FROM management_app.projects
  WHERE project_key = #{projectKey}
)

SELECT EXISTS (
  SELECT 1
  FROM management_app.projects
  WHERE project_key = #{projectKey}
    AND id != #{id}
)

SELECT COUNT(*)
FROM management_app.issues
WHERE project_id = #{projectId}
